function ensureProject(){const p=pj(); p.perms=p.perms||{}; p.members=p.members||{}; p.rolePerms=p.rolePerms||JSON.parse(JSON.stringify(roleTemplate)); Object.keys(roleTemplate).forEach(r=>p.rolePerms[r]=Object.assign({},roleTemplate[r],p.rolePerms[r]||{})); p.personPerms=p.personPerms||{}; p.boards=p.boards||[]; p.assets=p.assets||[{name:'Brand assets',type:'Folder',privacy:'Project'},{name:'Homepage board',type:'Whiteboard',privacy:'Project'}]; p.activity=p.activity||[{type:'ok',text:'Project hub opened and ready for work.',time:'Now'},{type:'chat',text:'Communication layers connected: Messages, Project Chat and Private Rooms.',time:'Today'}]; p.coreLog=p.coreLog||[{name:'Sorro AI',text:'I can read this project context and help plan tasks, access, whiteboards and next actions.',time:'Now'}]; p.approvals=p.approvals||[{id:Date.now()+1,title:'Homepage mockup approval',status:'Requested',owner:'Cristian',notes:'Needs final sign-off before this moves to Done.'},{id:Date.now()+2,title:'Thumbnail v3',status:'Changes needed',owner:'Ryan',notes:'Waiting on revised artwork direction.'}]; return p;}
