function addActivity(type,text){const p=ensureProject(); p.activity=p.activity||[]; p.activity.unshift({type,text,time:new Date().toLocaleString([], {hour:'2-digit',minute:'2-digit',day:'2-digit',month:'short'})}); p.activity=p.activity.slice(0,30);}
function hasPerm(personId,key){const p=ensureProject(); const role=p.members[personId]||'Guest'; const base=(p.rolePerms[role]||roleTemplate.Guest||{})[key]; const over=p.personPerms[personId]&&p.personPerms[personId][key]; return over==='allow'?true:over==='deny'?false:!!base;}

function show(id){$$('.project-tabs button').forEach(b=>b.classList.toggle('active',b.dataset.panel===id));$$('.project-panel').forEach(p=>p.classList.toggle('active',p.id===id)); if(id==='whiteboard') setTimeout(setupBoard,50); window.scrollTo({top:0,behavior:'smooth'});} 
function flashElement(el){if(!el)return; el.classList.add('csorro-target-flash'); el.scrollIntoView({behavior:'smooth',block:'center'}); setTimeout(()=>el.classList.remove('csorro-target-flash'),2200);} 
function openLinkedBlocker(){const p=ensureProject(); const approvals=(p.approvals||[]).filter(a=>a.status!=='Approved'); if(approvals.length){show('approvals'); setTimeout(()=>flashElement(document.querySelector('[data-approval-card="0"]')),80); return;} const task=p.tasks.find(t=>t.lane==='priority')||p.tasks[0]; if(task){show('tasks'); setTimeout(()=>flashElement(document.querySelector(`[data-id="${task.id}"]`)),80); return;} show('coreai');} 
function openLinkedSuggestion(kind){const p=ensureProject(); if(kind==='approvals') {show('approvals'); setTimeout(()=>flashElement(document.querySelector('[data-approval-card="0"]')),80); return;} if(kind==='tasks') {show('tasks'); const task=p.tasks.find(t=>t.lane==='priority')||p.tasks[0]; setTimeout(()=>flashElement(task?document.querySelector(`[data-id="${task.id}"]`):document.querySelector('#tasksBoard')),80); return;} if(kind==='files') {show('files'); setTimeout(()=>flashElement(document.querySelector('.asset-card-v40')),80); return;} if(kind==='activity') {show('activity'); setTimeout(()=>flashElement(document.querySelector('.timeline-item-v40')),80); return;} if(kind==='chat') {show('chat'); setTimeout(()=>flashElement(document.querySelector('#chatMessages')),80); return;} show('coreai');}

