function projectHealthData(){
  const p=ensureProject();
  const tasks=(p.tasks||[]).map(normaliseTask);
  const total=tasks.length||1;
  const done=tasks.filter(t=>t.lane==='done').length;
  const review=tasks.filter(t=>t.lane==='review').length;
  const priority=tasks.filter(t=>t.lane==='priority').length;
  const approvals=(p.approvals||[]);
  const approvalNeeds=approvals.filter(a=>a.status!=='Approved').length;
  const files=(p.assets||[]).length;
  const people=Object.keys(p.members||{}).length;
  const progress=Math.round((done/total)*100);
  const attention=Math.min(100, Math.round(priority*22 + approvalNeeds*18 + Math.max(0,3-people)*10));
  const health=Math.max(0, Math.min(100, 100-attention+Math.min(done*5,20)));
  return {total,done,review,priority,approvalNeeds,files,people,progress,attention,health};
}
function renderIntelligence(){
  const p=ensureProject(), d=projectHealthData();
  const headline=$('#intelligenceHeadline'), summary=$('#intelligenceSummary'), badge=$('#projectHealthBadge'), bars=$('#projectHealthBars');
  const needsReview=d.approvalNeeds+d.review;
  const status=d.health>70?'Healthy':d.health>45?'Needs attention':'Blocked';
  if(headline) headline.textContent = d.priority ? 'Priority work needs attention' : needsReview ? 'Review queue is active' : 'Project is moving cleanly';
  if(summary) summary.textContent = `${d.people} project people, ${d.total} task cards, ${d.files} files and ${d.approvalNeeds} approval item${d.approvalNeeds===1?'':'s'} waiting. Sorro AI is using live project data, not static text.`;
  if(badge){ badge.textContent=status; badge.className='mini-label '+(d.health>70?'green':d.health>45?'amber':'red'); }
  if(bars){
    bars.innerHTML = [
      ['Progress',d.progress,'project-health-good'],
      ['Health',d.health,d.health>45?'project-health-good':'project-health-warning'],
      ['Attention',d.attention,d.attention>50?'project-health-warning':'project-health-good']
    ].map(([label,val,cls])=>`<div class="health-line-v43 ${cls}"><span>${label}</span><span><i style="width:${Math.max(4,Math.min(100,val))}%"></i></span><b>${val}%</b></div>`).join('');
  }
  if($('#coreSays')){
    const items=[];
    if(d.priority) items.push(`<li class="warn"><span><b>${d.priority} priority task${d.priority===1?'':'s'}</b><small>Open Tasks and move the blocker forward.</small></span></li>`);
    if(d.approvalNeeds) items.push(`<li><span><b>${d.approvalNeeds} approval item${d.approvalNeeds===1?'':'s'} waiting</b><small>Review artwork, files or sign-off requests.</small></span></li>`);
    if(d.files) items.push(`<li class="ok"><span><b>${d.files} project file${d.files===1?'':'s'} connected</b><small>Files can be shared into chat or approvals.</small></span></li>`);
    items.push(`<li class="ok"><span><b>${d.people} people assigned</b><small>Use People to manage roles and custom permissions.</small></span></li>`);
    $('#coreSays').innerHTML='<ul>'+items.join('')+'</ul>';
  }
}
function renderProject(){const p=ensureProject(), w=ws(); const members=Object.keys(p.members||{}).length; const priority=p.tasks.filter(t=>t.lane==='priority').length; const active=p.tasks.filter(t=>t.lane!=='done').length; if($('#crumb')) $('#crumb').textContent=w.name+' / Project Hub'; if($('#projectTitle')) $('#projectTitle').textContent=p.name; if($('#projectIntro')) $('#projectIntro').textContent=p.intro; if($('#projectBlocker')) $('#projectBlocker').textContent=p.blocker; if($('#projectMeta')) $('#projectMeta').textContent=w.privacy+' workspace · '+members+' project people'; if($('#peopleMeta')) $('#peopleMeta').textContent=members+' project people'; if($('#phaseMeta')) $('#phaseMeta').textContent=p.milestone+' phase'; if($('#coreSays')) $('#coreSays').innerHTML='<ul><li><button class="intel-row" onclick="window.CSorroOpenLinkedSuggestion(\'approvals\')"><b>Approve thumbnail v3</b><small>Open linked approval</small></button></li><li><button class="intel-row" onclick="window.CSorroOpenLinkedSuggestion(\'tasks\')"><b>'+priority+' priority task'+(priority===1?'':'s')+'</b><small>Open Tasks and move the blocker forward.</small></button></li><li><button class="intel-row" onclick="window.CSorroOpenLinkedSuggestion(\'activity\')"><b>Recording in 22h</b><small>Open timeline context</small></button></li></ul>'; window.CSorroOpenLinkedSuggestion=openLinkedSuggestion; if($('#doneCount')) $('#doneCount').textContent=p.tasks.filter(t=>t.lane==='done').length; if($('#activeTasksCount')) $('#activeTasksCount').textContent=active||p.tasks.length; if($('#priorityCount')) $('#priorityCount').textContent=priority; if($('#peopleCount')) $('#peopleCount').textContent=members; if($('#nextMilestone')) $('#nextMilestone').textContent=p.milestone; if($('#milestoneSide')) $('#milestoneSide').textContent=p.milestone; if($('#todayPriority')) $('#todayPriority').innerHTML=(p.tasks.filter(t=>t.lane==='priority').slice(0,3).map(t=>`<label class="priority-row intelligence-link" onclick="window.CSorroOpenTaskFromOverview(${t.id})"><input type="checkbox"/><span><b>${esc(t.title)}</b><small>Due today · ${esc(t.owner)} · click to open task</small></span><em>${esc(t.colour||'blocker')}</em></label>`).join('')||'<p class="muted">No priority tasks yet.</p>'); if($('#recentActivity')) { const acts=(p.activity||[]).slice(0,6); $('#recentActivity').innerHTML=acts.length?acts.map(a=>`<div class="activity-v35 intelligence-link" onclick="window.CSorroOpenActivityItem('${esc(a.type||'activity')}')"><span class="${esc(a.type||'ok')}">${activityIcon(a.type)}</span><div><b>${esc(a.text)}</b><small>${esc(a.time)} · click to open source</small></div><i></i></div>`).join(''):'<p class="muted">No activity yet.</p>'; }; if($('#overviewWorkspace')) $('#overviewWorkspace').textContent=w.name+' · '+w.privacy; if($('#overviewProject')) $('#overviewProject').textContent=p.name+' · '+p.milestone; ['allowOpen','allowPrivate','allowBoard','allowTasks'].forEach(id=>{const el=$('#'+id); if(el){el.checked=!!p.perms[id]; el.onchange=()=>{p.perms[id]=el.checked; save();};}}); const sc=$('#projectShowcaseToggle'); if(sc){sc.checked=!!p.showcase; sc.onchange=()=>{p.showcase=sc.checked; $('#projectShowcase').classList.toggle('enabled',sc.checked); save();}; $('#projectShowcase').classList.toggle('enabled',!!p.showcase);} renderIntelligence(); }
function renderPeople(){const w=ws(), p=ensureProject(); const team=$('#projectTeamOverview'); if(team){team.innerHTML=Object.entries(p.members).map(([id,role])=>{const person=w.people.find(x=>x.id===id)||{name:id,role}; return `<div class="team-member-v35"><span class="avatar-mini">${esc(person.name[0])}</span><div><b>${esc(person.name)}</b><small>${esc(role)}</small></div><i></i></div>`}).join('')+'<button class="team-manage-btn" data-jump="team">Manage people →</button>'; team.querySelectorAll('[data-jump]').forEach(btn=>btn.onclick=()=>show(btn.dataset.jump));}
const wl=$('#workspacePeopleList'), pl=$('#projectPeopleList'); if(!wl)return; wl.innerHTML=w.people.map(person=>`<div class="person-row ${p.members[person.id]?'team-assigned':''}"><div class="person-left"><span class="avatar-mini">${esc(person.name[0])}</span><div><b>${esc(person.name)}</b><p class="muted">${esc(person.role)} ${p.members[person.id]?'· assigned to project':''}</p></div></div><div class="person-actions"><button class="chip-btn" data-quick="${person.id}">Assign</button></div></div>`).join(''); wl.querySelectorAll('[data-quick]').forEach(b=>b.onclick=()=>{p.members[b.dataset.quick]=w.people.find(x=>x.id===b.dataset.quick).role; save(); renderPeople(); renderRooms(); renderTasks(); renderProject();}); pl.innerHTML=Object.entries(p.members).map(([id,role])=>{const person=w.people.find(x=>x.id===id)||{name:id}; const perms=permKeys.map(([k,label])=>`<label><input type="checkbox" data-person-perm="${id}:${k}" ${hasPerm(id,k)?'checked':''}/> ${label}</label>`).join(''); return `<div class="person-row person-permission-row"><div class="person-left"><span class="avatar-mini">${esc(person.name[0])}</span><div><b>${esc(person.name)}</b><p class="muted">${esc(role)} · custom overrides available</p></div></div><button class="chip-btn" data-unassign="${id}">Remove</button><div class="perm-mini-grid">${perms}</div></div>`}).join(''); pl.querySelectorAll('[data-unassign]').forEach(b=>b.onclick=()=>{delete p.members[b.dataset.unassign]; delete p.personPerms[b.dataset.unassign]; save(); renderPeople(); renderRooms(); renderTasks(); renderProject();}); pl.querySelectorAll('[data-person-perm]').forEach(input=>input.onchange=()=>{const [id,k]=input.dataset.personPerm.split(':'); p.personPerms[id]=p.personPerms[id]||{}; const role=p.members[id]||'Guest'; const roleDefault=!!(p.rolePerms[role]&&p.rolePerms[role][k]); p.personPerms[id][k]=input.checked===roleDefault?'inherit':(input.checked?'allow':'deny'); if(p.personPerms[id][k]==='inherit')delete p.personPerms[id][k]; save(); renderPeople();}); const ap=$('#assignPerson'); if(ap) ap.innerHTML=w.people.map(x=>`<option value="${esc(x.id)}">${esc(x.name)}</option>`).join(''); const to=$('#taskOwner'); if(to) to.innerHTML=Object.keys(p.members).map(id=>{const person=w.people.find(x=>x.id===id)||{name:id}; return `<option>${esc(person.name)}</option>`}).join('')||'<option>Cristian</option>'; const rp=$('#roomPeople'); if(rp) rp.innerHTML=Object.keys(p.members).map(id=>{const person=w.people.find(x=>x.id===id)||{name:id}; return `<label><input type="checkbox" value="${esc(person.name)}"/> ${esc(person.name)}</label>`}).join(''); renderRolePerms();}
function renderRolePerms(){const host=$('#rolePerms'); if(!host)return; const p=ensureProject(); host.innerHTML=Object.keys(p.rolePerms).map(role=>`<details class="role-perm"><summary>${esc(role)} permissions</summary><div class="perm-mini-grid">${permKeys.map(([k,label])=>`<label><input type="checkbox" data-role-perm="${esc(role)}:${k}" ${p.rolePerms[role][k]?'checked':''}/> ${label}</label>`).join('')}</div></details>`).join(''); host.querySelectorAll('[data-role-perm]').forEach(i=>i.onchange=()=>{const [role,k]=i.dataset.rolePerm.split(':'); p.rolePerms[role][k]=i.checked; save(); renderPeople();});}
