function roomIsPrivate(r){return !(r.members||[]).includes('Everyone');}
function ensureRooms(){const p=ensureProject(); p.rooms=p.rooms||{}; if(!p.rooms.open)p.rooms.open={name:'# Open Project Chat',members:['Everyone'],type:'open',messages:[]}; Object.values(p.rooms).forEach(r=>{r.type=r.type||(roomIsPrivate(r)?'private':'open'); r.messages=r.messages||[];}); if(!p.rooms[state.activeRoom])state.activeRoom='open'; return p.rooms;}
function renderRooms(){const rooms=ensureRooms(), wrap=$('#roomButtons'); if(!wrap)return; const entries=Object.entries(rooms); const open=entries.filter(([id,r])=>!roomIsPrivate(r)); const priv=entries.filter(([id,r])=>roomIsPrivate(r)); const html=(label,items)=>`<div class="room-group-label">${label}</div>`+items.map(([id,r])=>`<button class="room room-v37 ${state.activeRoom===id?'active':''} ${roomIsPrivate(r)?'private':'open'}" data-room="${id}"><span class="room-icon">${roomIsPrivate(r)?'🔒':'#'}</span><span><b>${esc(r.name)}</b><small>${roomIsPrivate(r)?'Private · '+r.members.map(personNameById).join(', '):'Visible to project team'}</small></span><span class="room-count">${roomIsPrivate(r)?r.members.length:'All'}</span></button>`).join(''); wrap.innerHTML=html('Open rooms',open)+html('Private rooms',priv); wrap.querySelectorAll('.room').forEach(b=>b.onclick=()=>{state.activeRoom=b.dataset.room;save();renderRooms();renderMessages();});}
function renderMessages(){const p=ensureProject(), r=p.rooms[state.activeRoom]||p.rooms.open; const privateRoom=roomIsPrivate(r); const title=$('#roomTitle'), access=$('#roomAccess'), badge=$('#roomTypeBadge'), summary=$('#roomAccessSummary'), panel=$('#roomMembersPanel'), createPeople=$('#roomPeople'), accessPanel=document.querySelector('.chat-access-panel'); if(title)title.textContent=r.name; if(access)access.textContent=privateRoom?'Only selected project members can see and use this room.':'Everyone assigned to this project can see and use this room.'; if(badge){badge.textContent=privateRoom?'Private Room':'Open Project Chat'; badge.className='mini-label '+(privateRoom?'private':'open');} if(summary)summary.textContent=privateRoom?'Private: choose exactly who can see this chat.':'Open: visible to every person assigned to this project.'; if(accessPanel)accessPanel.classList.toggle('private-room',privateRoom); const projectPeople=Object.keys(p.members||{}); if(panel){panel.innerHTML=projectPeople.map(id=>`<label class="room-access-row"><span class="avatar-mini">${esc(personNameById(id)[0]||'?')}</span><span><b>${esc(personNameById(id))}</b><small>${esc(p.members[id]||'Member')}</small></span><input type="checkbox" data-room-member="${id}" ${(!privateRoom || r.members.includes(id)||r.members.includes(personNameById(id)))?'checked':''} ${privateRoom?'':'disabled'}/></label>`).join('')+(privateRoom?'<button class="btn-secondary" id="saveRoomAccess" type="button">Save room access</button>':''); const saveAccess=$('#saveRoomAccess'); if(saveAccess)saveAccess.onclick=()=>{r.members=$$('#roomMembersPanel input:checked').map(i=>i.dataset.roomMember); if(!r.members.length){alert('A private room needs at least one member.'); return;} r.messages.push({name:'Sorro AI',text:'Room access updated: '+r.members.map(personNameById).join(', '),time:new Date().toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'})}); save(); renderRooms(); renderMessages();};}
 if(createPeople){createPeople.innerHTML=projectPeople.map(id=>`<label><input type="checkbox" value="${id}"/><span>${esc(personNameById(id))} <small class="muted">${esc(p.members[id])}</small></span></label>`).join('');}
 const msg=$('#messages'); if(!msg)return; msg.innerHTML=(r.messages||[]).map(m=>`<div class="message ${m.name==='You'?'me':''}"><b>${esc(m.name)}</b>${esc(m.text)}<small>${esc(m.time)}</small></div>`).join(''); msg.scrollTop=msg.scrollHeight;}
