$('#addRoom')?.addEventListener('click',()=>{const name=$('#roomName').value.trim(); if(!name)return; const members=$$('#roomPeople input:checked').map(i=>i.value); if(!members.length){alert('Choose who can see this private chat first.'); return;} const id=name.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'')+'-'+Date.now().toString(36); pj().rooms[id]={name:'Private · '+name,members,type:'private',messages:[{name:'Sorro AI',text:'Private room created for '+members.map(personNameById).join(', '),time:new Date().toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'})}]}; state.activeRoom=id; addActivity('chat','Private room created: '+name); $('#roomName').value=''; save(); renderRooms();renderMessages();renderProject();});
