function normaliseTask(t){
  t.priority=t.priority||({red:'Urgent',amber:'High',blue:'Normal',green:'Low'}[t.colour]||'Normal');
  t.due=t.due||'';
  t.labels=t.labels||((t.colour? t.colour : '')+(t.links? ', '+t.links:''));
  t.checklist=t.checklist||'';
  t.comments=t.comments||[];
  return t;
}
function taskChecklistProgress(t){
  const lines=String(t.checklist||'').split('\n').map(x=>x.trim()).filter(Boolean);
  if(!lines.length)return '';
  const done=lines.filter(x=>/^\[x\]|^x\s|^✓/i.test(x)).length;
  return `${done}/${lines.length}`;
}
function taskMatches(t){
  const q=($('#taskSearch')?.value||'').toLowerCase();
  const f=$('#taskFilter')?.value||'all';
  const text=[t.title,t.info,t.owner,t.priority,t.labels,t.links].join(' ').toLowerCase();
  return (!q||text.includes(q)) && (f==='all'||t.priority===f);
}
function renderTasks(){
  const p=pj(), board=$('#tasksBoard'); if(!board)return;
  p.tasks.forEach(normaliseTask);
  const lanes=[['priority','Priority'],['doing','In Progress'],['review','Review'],['done','Done']];
  board.innerHTML=lanes.map(([id,name])=>{
    const laneTasks=p.tasks.filter(t=>t.lane===id&&taskMatches(t));
    return `<div class="lane lane-v41" data-lane="${id}"><h3>${name}<span>${laneTasks.length}</span></h3>${laneTasks.map(t=>taskHtml(t)).join('')||'<p class="empty-lane-v41">Drop tasks here</p>'}</div>`;
  }).join('');
  board.querySelectorAll('.task-card').forEach(card=>{
    card.draggable=true;
    card.ondragstart=e=>e.dataTransfer.setData('text/plain',card.dataset.id);
    card.onclick=e=>{if(!e.target.closest('button'))openTask(+card.dataset.id);};
  });
  board.querySelectorAll('.lane').forEach(lane=>{
    lane.ondragover=e=>{e.preventDefault(); lane.classList.add('drop-ready');};
    lane.ondragleave=()=>lane.classList.remove('drop-ready');
    lane.ondrop=e=>{e.preventDefault(); lane.classList.remove('drop-ready'); const id=+e.dataTransfer.getData('text/plain'); const t=p.tasks.find(x=>x.id===id); if(t){t.lane=lane.dataset.lane; addActivity('task', t.title+' moved to '+lane.dataset.lane); save(); renderAll();}};
  });
}
function taskHtml(t){
  normaliseTask(t);
  const progress=taskChecklistProgress(t);
  const labels=String(t.labels||'').split(',').map(x=>x.trim()).filter(Boolean).slice(0,3);
  const priorityClass='prio-'+String(t.priority||'Normal').toLowerCase();
  return `<article class="task-card task-card-v41 ${priorityClass}" draggable="true" data-id="${t.id}" data-colour="${esc(t.colour)}"><div class="task-title-row"><b>${esc(t.title)}</b><span>${esc(t.lane)}</span></div><p>${esc(t.info)}</p><div class="task-meta"><span class="tag owner">${esc(t.owner)}</span><span class="tag priority">${esc(t.priority)}</span>${t.due?`<span class="tag due">Due ${esc(t.due)}</span>`:''}${progress?`<span class="tag checklist">Checklist ${esc(progress)}</span>`:''}</div>${labels.length?`<div class="task-labels-v41">${labels.map(l=>`<span>${esc(l)}</span>`).join('')}</div>`:''}<div class="task-actions-v41"><button class="chip-btn" onclick="window.CSorroMoveTask(${t.id},'priority')">Priority</button><button class="chip-btn" onclick="window.CSorroMoveTask(${t.id},'doing')">Progress</button><button class="chip-btn" onclick="window.CSorroMoveTask(${t.id},'review')">Review</button><button class="chip-btn" onclick="window.CSorroMoveTask(${t.id},'done')">Done</button></div></article>`;
}
window.CSorroMoveTask=(id,lane)=>{const t=pj().tasks.find(x=>x.id===id); if(t){t.lane=lane; addActivity('task', t.title+' moved to '+lane); save(); renderAll();}}; window.CSorroOpenTaskFromOverview=(id)=>{show('tasks'); setTimeout(()=>{const el=document.querySelector(`[data-id="${id}"]`); flashElement(el); if(el) openTask(id);},120);};
