$('#createTask')?.addEventListener('click',()=>{const title=$('#taskTitle').value.trim(); if(!title)return; pj().tasks.unshift({id:Date.now(),title,info:$('#taskInfo').value.trim(),lane:'priority',owner:$('#taskOwner').value,priority:$('#taskPriority')?.value||'Normal',due:$('#taskDue')?.value||'',colour:$('#taskColour').value,labels:$('#taskLabels')?.value.trim()||'',links:$('#taskLinks').value.trim(),checklist:$('#taskChecklist')?.value.trim()||'',comments:[]}); addActivity('task','New task created: '+title); ['taskTitle','taskInfo','taskLinks','taskLabels','taskChecklist','taskDue'].forEach(id=>{const el=$('#'+id); if(el)el.value='';}); save(); renderAll();});
let activeTask=null; function openTask(id){
  activeTask=pj().tasks.find(t=>t.id===id); if(!activeTask)return; normaliseTask(activeTask);
  $('#modalTitle').textContent=activeTask.title; $('#modalTaskTitle').value=activeTask.title; $('#modalTaskInfo').value=activeTask.info||''; $('#modalTaskLinks').value=activeTask.links||''; $('#modalTaskChecklist').value=activeTask.checklist||''; $('#modalTaskComment').value='';
  if($('#modalTaskLane')) $('#modalTaskLane').textContent=activeTask.lane;
  if($('#modalTaskLaneSelect')) $('#modalTaskLaneSelect').value=activeTask.lane;
  if($('#modalTaskPriority')) $('#modalTaskPriority').value=activeTask.priority||'Normal';
  if($('#modalTaskDue')) $('#modalTaskDue').value=activeTask.due||'';
  if($('#modalTaskLabels')) $('#modalTaskLabels').value=activeTask.labels||'';
  const ownerSel=$('#modalTaskOwner'); if(ownerSel){ownerSel.innerHTML=Object.keys(pj().members).map(id=>{const person=ws().people.find(x=>x.id===id)||{name:id}; return `<option ${person.name===activeTask.owner?'selected':''}>${esc(person.name)}</option>`}).join('')||`<option>${esc(activeTask.owner||'Cristian')}</option>`;}
  const comments=$('#modalTaskComments'); if(comments){comments.innerHTML=(activeTask.comments||[]).map(c=>`<div class="task-comment-v41">${esc(c)}</div>`).join('')||'<p class="muted">No comments yet.</p>';}
  $('#taskModal').classList.add('open');
}
$('#closeTask')?.addEventListener('click',()=>$('#taskModal').classList.remove('open'));
$('#saveTaskDetail')?.addEventListener('click',()=>{if(!activeTask)return; activeTask.title=$('#modalTaskTitle').value; activeTask.info=$('#modalTaskInfo').value; activeTask.links=$('#modalTaskLinks').value; activeTask.checklist=$('#modalTaskChecklist').value; activeTask.lane=$('#modalTaskLaneSelect')?.value||activeTask.lane; activeTask.owner=$('#modalTaskOwner')?.value||activeTask.owner; activeTask.priority=$('#modalTaskPriority')?.value||activeTask.priority; activeTask.due=$('#modalTaskDue')?.value||''; activeTask.labels=$('#modalTaskLabels')?.value||''; const c=$('#modalTaskComment').value.trim(); if(c)(activeTask.comments||(activeTask.comments=[])).push(c); addActivity('task','Task updated: '+activeTask.title); $('#taskModal').classList.remove('open'); save(); renderAll();});
