function renderNotes(){const p=pj(), board=$('#stickyBoard'); if(!board)return; board.innerHTML=p.notes.map((n,i)=>`<article class="sticky"><textarea data-note="${i}">${esc(n)}</textarea><footer><span>Sticky note</span><button class="chip-btn" data-task="${i}">Task</button><button class="chip-btn" data-del="${i}">Delete</button></footer></article>`).join(''); board.querySelectorAll('textarea').forEach(t=>t.oninput=()=>{p.notes[+t.dataset.note]=t.value;save();}); board.querySelectorAll('[data-del]').forEach(b=>b.onclick=()=>{p.notes.splice(+b.dataset.del,1);save();renderNotes();}); board.querySelectorAll('[data-task]').forEach(b=>b.onclick=()=>{const text=p.notes[+b.dataset.task]; p.tasks.unshift({id:Date.now(),title:text.slice(0,50)||'Sticky note task',info:text,lane:'priority',owner:'Cristian',colour:'amber',links:'',checklist:'',comments:[]}); save(); renderTasks(); show('tasks');});}
