function renderMail(){const p=pj(), list=$('#mailList'), body=$('#mailBody'); if(!list)return; p.mail=p.mail||[]; list.innerHTML=p.mail.map((m,i)=>`<div class="mail-item ${i===0?'active':''}" data-mail="${i}"><b>${esc(m.subject)}</b><p class="muted">From ${esc(m.from)}</p></div>`).join(''); function open(i){const m=p.mail[i]||{subject:'No messages',from:'Sorro AI',body:'No OS messages yet.'}; body.innerHTML=`<h2>${esc(m.subject)}</h2><p class="muted">From ${esc(m.from)} · OS Message · ${esc(ws().name)} / ${esc(p.name)}</p><p>${esc(m.body)}</p><button class="btn-secondary">Reply</button>`; list.querySelectorAll('.mail-item').forEach((x,n)=>x.classList.toggle('active',n===i));} list.querySelectorAll('.mail-item').forEach(x=>x.onclick=()=>open(+x.dataset.mail)); open(0);}
