function renderBoards(){const p=ensureProject(), list=$('#savedBoardsList'); if(!list)return; p.boards=p.boards||[]; const nameEl=$('#activeBoardName'), metaEl=$('#activeBoardMeta'); const active=p.boards.find(x=>x.id===p.activeBoardId); if(nameEl) nameEl.textContent=active?active.name:'Unsaved board'; if(metaEl) metaEl.textContent=active?('Last saved '+active.updated+' · '+((active.versions||[]).length+1)+' version(s)'):'Working canvas'; if(!p.boards.length){list.innerHTML='<div class="empty-board-v44"><b>No saved boards yet.</b><small>Sketch or upload an image, then hit Save version. Boards stay attached to this project.</small></div>'; return;} list.innerHTML=p.boards.map(b=>`<article class="saved-board saved-board-v44 ${p.activeBoardId===b.id?'active':''}"><div><b>${esc(b.name)}</b><small>Updated ${esc(b.updated||b.created)} · ${((b.versions||[]).length+1)} version(s)</small></div><div class="board-actions-v44"><button class="chip-btn" data-load-board="${b.id}">Open</button><button class="chip-btn" data-share-board="${b.id}">Share</button><button class="chip-btn" data-duplicate-board="${b.id}">Duplicate</button><button class="chip-btn" data-export-board="${b.id}">Export</button><button class="chip-btn danger" data-delete-board="${b.id}">Delete</button></div></article>`).join(''); list.querySelectorAll('[data-load-board]').forEach(btn=>btn.onclick=()=>{const b=p.boards.find(x=>x.id==btn.dataset.loadBoard); if(b){p.board=b.data; p.activeBoardId=b.id; save(); boardReadyFor=''; setupBoard(); renderBoards(); addActivity('board','Whiteboard opened: '+b.name); renderActivityFull();}}); list.querySelectorAll('[data-share-board]').forEach(btn=>btn.onclick=()=>{const b=p.boards.find(x=>x.id==btn.dataset.shareBoard); if(!b)return; const room=p.rooms[state.activeRoom]||p.rooms.open; room.messages.push({name:'You',text:'[Whiteboard] '+b.name+' shared into project chat.',time:new Date().toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'})}); addActivity('chat','Whiteboard shared to chat: '+b.name); save(); renderMessages(); renderActivityFull(); show('chat');}); list.querySelectorAll('[data-duplicate-board]').forEach(btn=>btn.onclick=()=>{const b=p.boards.find(x=>x.id==btn.dataset.duplicateBoard); if(!b)return; const copy={...b,id:Date.now(),name:b.name+' copy',created:new Date().toLocaleString(),updated:new Date().toLocaleString(),versions:[...(b.versions||[])]}; p.boards.unshift(copy); addActivity('board','Whiteboard duplicated: '+copy.name); save(); renderBoards(); renderActivityFull();}); list.querySelectorAll('[data-export-board]').forEach(btn=>{btn.onclick=()=>{const b=p.boards.find(x=>x.id==btn.dataset.exportBoard); if(b) downloadBoard(b.data,(b.name||'whiteboard').replace(/[^a-z0-9]+/gi,'-').toLowerCase()+'.png');};}); list.querySelectorAll('[data-delete-board]').forEach(btn=>btn.onclick=()=>{const b=p.boards.find(x=>x.id==btn.dataset.deleteBoard); if(!b)return; if(confirm('Delete this saved whiteboard?')){p.boards=p.boards.filter(x=>x.id!=b.id); if(p.activeBoardId===b.id){p.activeBoardId=null;p.board=null;} addActivity('board','Whiteboard deleted: '+b.name); save(); renderBoards(); boardReadyFor=''; setupBoard(); renderActivityFull();}});}
function downloadBoard(data,name){const a=document.createElement('a'); a.href=data; a.download=name||'csorro-whiteboard.png'; document.body.appendChild(a); a.click(); a.remove();}
function renderCore(){const p=ensureProject(), dialog=$('#coreDialog'); if(!dialog)return; dialog.innerHTML=p.coreLog.map(m=>`<div class="message ${m.name==='You'?'me':''}"><b>${esc(m.name)}</b>${esc(m.text)}<small>${esc(m.time)}</small></div>`).join(''); dialog.scrollTop=dialog.scrollHeight;}
function coreReply(q){const p=ensureProject(), w=ws(); const lower=q.toLowerCase(); if(lower.includes('task')&&lower.includes('create')){p.tasks.unshift({id:Date.now(),title:'Sorro AI task: '+q.replace(/^create a task/i,'').trim().slice(0,70),info:'Created from Sorro AI dialogue. Edit the task card to add images, links and checklist.',lane:'priority',owner:'Cristian',colour:'amber',links:'',checklist:'',comments:['Created by Sorro AI prototype']}); return 'I created a priority task in this project. Open Tasks to edit the details, owner, links and checklist.';} if(lower.includes('attention')||lower.includes('today')) { const d=projectHealthData(); return 'Today: '+p.blocker+'. '+d.priority+' priority task(s), '+d.approvalNeeds+' approval item(s), '+d.files+' project file(s), '+Object.keys(p.members).length+' project people and '+(p.boards||[]).length+' saved whiteboard(s).'; } if(lower.includes('summar')) return p.name+' is in '+p.milestone+' stage inside '+w.name+'. Current blocker: '+p.blocker+'. '+p.tasks.length+' task cards and '+Object.keys(p.members).length+' people are connected.'; if(lower.includes('access')||lower.includes('permission')) return 'Access is controlled by workspace membership first, then project role, then per-person overrides. Owners can allow a guest to edit only sticky notes, tasks or whiteboards without upgrading their full role.'; if(lower.includes('whiteboard')) return 'Whiteboards save to this project only. You can reopen or delete them from Project Whiteboards. Later they can also attach to tasks or assets.'; return 'I understand the project context. I can help plan next actions, explain permissions, summarise the project, create a task, or review saved whiteboards.';}
